import{_ as l,c as i,o as a,ag as o}from"./chunks/framework.dvv-DFtf.js";const u=JSON.parse('{"title":"邮件客户端配置","description":"","frontmatter":{},"headers":[],"relativePath":"webmail/client-setup.md","filePath":"webmail/client-setup.md","lastUpdated":null}'),r={name:"webmail/client-setup.md"};function s(d,t,e,n,c,h){return a(),i("div",null,[...t[0]||(t[0]=[o(`<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /webmail\\client-setup.md for this page in Markdown format</div><h1 id="邮件客户端配置" tabindex="-1">邮件客户端配置 <a class="header-anchor" href="#邮件客户端配置" aria-label="Permalink to &quot;邮件客户端配置&quot;">​</a></h1><h2 id="服务器参数" tabindex="-1">服务器参数 <a class="header-anchor" href="#服务器参数" aria-label="Permalink to &quot;服务器参数&quot;">​</a></h2><p>配置任何邮件客户端时，统一使用以下参数：</p><table tabindex="0"><thead><tr><th>类型</th><th>服务器地址</th><th>端口</th><th>加密方式</th></tr></thead><tbody><tr><td><strong>收件（IMAP）</strong></td><td>mail.lurus.cn</td><td>993</td><td>SSL/TLS</td></tr><tr><td><strong>发件（SMTP）</strong></td><td>mail.lurus.cn</td><td>587</td><td>STARTTLS</td></tr><tr><td><strong>发件（SMTP）备用</strong></td><td>mail.lurus.cn</td><td>465</td><td>SSL/TLS</td></tr></tbody></table><ul><li><strong>用户名</strong>：完整邮箱地址，如 <code>zhangsan@lurus.cn</code></li><li><strong>密码</strong>：你的 Webmail 登录密码</li></ul><hr><h2 id="microsoft-outlook" tabindex="-1">Microsoft Outlook <a class="header-anchor" href="#microsoft-outlook" aria-label="Permalink to &quot;Microsoft Outlook&quot;">​</a></h2><h3 id="outlook-for-windows-mac-新版" tabindex="-1">Outlook for Windows / Mac（新版） <a class="header-anchor" href="#outlook-for-windows-mac-新版" aria-label="Permalink to &quot;Outlook for Windows / Mac（新版）&quot;">​</a></h3><ol><li>打开 Outlook，点击「<strong>文件</strong>」→「<strong>添加账户</strong>」</li><li>输入邮箱地址 <code>your@lurus.cn</code>，点击「<strong>连接</strong>」</li><li>选择「<strong>IMAP</strong>」</li><li>填写收件服务器信息： <ul><li>服务器：<code>mail.lurus.cn</code></li><li>端口：<code>993</code></li><li>加密：<code>SSL/TLS</code></li></ul></li><li>填写发件服务器信息： <ul><li>服务器：<code>mail.lurus.cn</code></li><li>端口：<code>587</code></li><li>加密：<code>STARTTLS</code></li></ul></li><li>输入密码，点击「<strong>连接</strong>」</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>如果自动发现失败，在第 2 步点击「高级选项」→「手动配置账户」。</p></div><hr><h2 id="apple-mail-macos-ios" tabindex="-1">Apple Mail（macOS / iOS） <a class="header-anchor" href="#apple-mail-macos-ios" aria-label="Permalink to &quot;Apple Mail（macOS / iOS）&quot;">​</a></h2><h3 id="macos" tabindex="-1">macOS <a class="header-anchor" href="#macos" aria-label="Permalink to &quot;macOS&quot;">​</a></h3><ol><li>打开「<strong>邮件</strong>」App</li><li>菜单栏「<strong>邮件</strong>」→「<strong>添加账户</strong>」</li><li>选择「<strong>其他邮件账户</strong>」，点击「继续」</li><li>填写： <ul><li>姓名：你的姓名</li><li>邮件地址：<code>your@lurus.cn</code></li><li>密码：登录密码</li></ul></li><li>点击「登录」，如自动发现失败则进入手动配置： <ul><li>账户类型：<strong>IMAP</strong></li><li>邮件服务器：<code>mail.lurus.cn</code></li><li>用户名：完整邮箱地址</li></ul></li></ol><p>完成后系统会自动配置 SMTP 发件服务器。</p><h3 id="ios-iphone-ipad" tabindex="-1">iOS（iPhone / iPad） <a class="header-anchor" href="#ios-iphone-ipad" aria-label="Permalink to &quot;iOS（iPhone / iPad）&quot;">​</a></h3><ol><li>「<strong>设置</strong>」→「<strong>邮件</strong>」→「<strong>账户</strong>」→「<strong>添加账户</strong>」</li><li>选择「<strong>其他</strong>」→「<strong>添加邮件账户</strong>」</li><li>填写名称、邮件地址、密码、描述（随意填）</li><li>切换到「<strong>IMAP</strong>」选项卡： <ul><li>收件主机名：<code>mail.lurus.cn</code></li><li>用户名：完整邮箱地址</li><li>密码：登录密码</li></ul></li><li>发件（SMTP）： <ul><li>主机名：<code>mail.lurus.cn</code></li><li>用户名：完整邮箱地址</li><li>密码：登录密码</li></ul></li><li>点击「<strong>存储</strong>」</li></ol><hr><h2 id="mozilla-thunderbird" tabindex="-1">Mozilla Thunderbird <a class="header-anchor" href="#mozilla-thunderbird" aria-label="Permalink to &quot;Mozilla Thunderbird&quot;">​</a></h2><ol><li>打开 Thunderbird，点击「<strong>账户设置</strong>」→「<strong>添加邮件账户</strong>」</li><li>填写姓名、邮件地址、密码</li><li>点击「<strong>手动配置</strong>」</li><li>填写：</li></ol><p><strong>收件服务器（IMAP）</strong>：</p><table tabindex="0"><thead><tr><th>字段</th><th>值</th></tr></thead><tbody><tr><td>服务器名</td><td><code>mail.lurus.cn</code></td></tr><tr><td>端口</td><td><code>993</code></td></tr><tr><td>SSL</td><td><code>SSL/TLS</code></td></tr><tr><td>认证</td><td><code>正常密码</code></td></tr></tbody></table><p><strong>发件服务器（SMTP）</strong>：</p><table tabindex="0"><thead><tr><th>字段</th><th>值</th></tr></thead><tbody><tr><td>服务器名</td><td><code>mail.lurus.cn</code></td></tr><tr><td>端口</td><td><code>587</code></td></tr><tr><td>SSL</td><td><code>STARTTLS</code></td></tr><tr><td>认证</td><td><code>正常密码</code></td></tr></tbody></table><ol start="5"><li>点击「<strong>重新测试</strong>」确认连接，然后「<strong>完成</strong>」</li></ol><hr><h2 id="android-gmail-app" tabindex="-1">Android Gmail App <a class="header-anchor" href="#android-gmail-app" aria-label="Permalink to &quot;Android Gmail App&quot;">​</a></h2><p>Gmail App 支持添加 IMAP 账户：</p><ol><li>打开 Gmail，点击左上角菜单 → 滑到最底「<strong>添加账户</strong>」</li><li>选择「<strong>其他</strong>」</li><li>输入邮箱地址，点击「<strong>下一步</strong>」</li><li>选择「<strong>个人 (IMAP)</strong>」</li><li>输入密码</li><li>收件服务器设置： <ul><li>服务器：<code>mail.lurus.cn</code></li><li>端口：<code>993</code></li><li>安全类型：<code>SSL/TLS</code></li></ul></li><li>发件服务器设置： <ul><li>SMTP 服务器：<code>mail.lurus.cn</code></li><li>端口：<code>587</code></li><li>安全类型：<code>STARTTLS</code></li><li>需要登录：勾选</li></ul></li><li>点击「<strong>下一步</strong>」完成配置</li></ol><hr><h2 id="日历同步-caldav" tabindex="-1">日历同步（CalDAV） <a class="header-anchor" href="#日历同步-caldav" aria-label="Permalink to &quot;日历同步（CalDAV）&quot;">​</a></h2><p>在支持 CalDAV 的客户端（Apple Calendar、GNOME Calendar、Thunderbird）中添加：</p><table tabindex="0"><thead><tr><th>参数</th><th>值</th></tr></thead><tbody><tr><td>服务器 URL</td><td><code>https://mail.lurus.cn/dav/</code></td></tr><tr><td>用户名</td><td>完整邮箱地址</td></tr><tr><td>密码</td><td>登录密码</td></tr></tbody></table><p><strong>Apple Calendar（macOS）步骤</strong>：</p><ol><li>菜单「<strong>文件</strong>」→「<strong>添加账户</strong>」→「<strong>其他 CalDAV 账户</strong>」</li><li>填写服务器 URL、用户名、密码</li><li>点击「登录」</li></ol><hr><h2 id="联系人同步-carddav" tabindex="-1">联系人同步（CardDAV） <a class="header-anchor" href="#联系人同步-carddav" aria-label="Permalink to &quot;联系人同步（CardDAV）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>参数</th><th>值</th></tr></thead><tbody><tr><td>服务器 URL</td><td><code>https://mail.lurus.cn/dav/</code></td></tr><tr><td>用户名</td><td>完整邮箱地址</td></tr><tr><td>密码</td><td>登录密码</td></tr></tbody></table><p><strong>Apple Contacts（macOS）步骤</strong>：</p><ol><li>通讯录 App → 菜单「<strong>通讯录</strong>」→「<strong>添加账户</strong>」→「<strong>其他 CardDAV 账户</strong>」</li><li>填写服务器地址、用户名、密码</li></ol><hr><h2 id="配置验证" tabindex="-1">配置验证 <a class="header-anchor" href="#配置验证" aria-label="Permalink to &quot;配置验证&quot;">​</a></h2><p>配置完成后，可通过以下方式验证：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 测试 IMAP 连接</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openssl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> s_client</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -connect</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mail.lurus.cn:993</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -quiet</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 看到 &quot;220 ... ESMTP&quot; 即连接成功</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 测试 SMTP 连接</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openssl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> s_client</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -connect</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mail.lurus.cn:465</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -quiet</span></span></code></pre></div><p>或直接在客户端「<strong>测试账户设置</strong>」，看到收件和发件均为绿色勾即配置成功。</p>`,46)])])}const g=l(r,[["render",s]]);export{u as __pageData,g as default};
